import{_ as e,a as t,b as i}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as d,o as n,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Menambahkan Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/cloudflare-r2.md","filePath":"id-ID/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),o={name:"id-ID/upload/cloudflare-r2.md"};function u(c,a,s,m,h,b){return n(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="menambahkan-cloudflare-r2-channel" tabindex="-1">Menambahkan Cloudflare R2 Channel <a class="header-anchor" href="#menambahkan-cloudflare-r2-channel" aria-label="Permalink to &quot;Menambahkan Cloudflare R2 Channel&quot;">​</a></h1><h2 id="paling-cocok-untuk" tabindex="-1">Paling Cocok Untuk <a class="header-anchor" href="#paling-cocok-untuk" aria-label="Permalink to &quot;Paling Cocok Untuk&quot;">​</a></h2><p>Gunakan Cloudflare R2 saat:</p><ul><li>ImgBed site Anda sudah deploy di Cloudflare dan Anda ingin menyimpan files di R2 bucket dalam Cloudflare account yang sama.</li><li>Anda tidak ingin mengatur S3 endpoint, access key, dan secret key secara terpisah.</li><li>Anda ingin proses baca/tulis lewat Worker atau Pages R2 binding dengan setup minimal.</li></ul><p>Singkatnya:</p><p>R2 channel tidak dibuat manual di ImgBed admin panel. Anda harus bind R2 bucket ke Cloudflare project terlebih dahulu, dan binding variable name wajib <code>img_r2</code>.</p><h2 id="yang-perlu-disiapkan-sebelum-mulai" tabindex="-1">Yang Perlu Disiapkan Sebelum Mulai <a class="header-anchor" href="#yang-perlu-disiapkan-sebelum-mulai" aria-label="Permalink to &quot;Yang Perlu Disiapkan Sebelum Mulai&quot;">​</a></h2><ul><li>Cloudflare account.</li><li>R2 bucket yang sudah ada.</li><li>Permission untuk mengelola Cloudflare project tempat ImgBed dideploy.</li></ul><h2 id="konfigurasi-di-cloudflare" tabindex="-1">Konfigurasi di Cloudflare <a class="header-anchor" href="#konfigurasi-di-cloudflare" aria-label="Permalink to &quot;Konfigurasi di Cloudflare&quot;">​</a></h2><h3 id="_1-buat-r2-bucket" tabindex="-1">1. Buat R2 Bucket <a class="header-anchor" href="#_1-buat-r2-bucket" aria-label="Permalink to &quot;1. Buat R2 Bucket&quot;">​</a></h3><ol><li>Log in ke Cloudflare Dashboard.</li><li>Buka <code>R2 Object Storage</code>.</li><li>Klik Create bucket.</li><li>Pilih bucket name, misalnya <code>imgbed</code>.</li></ol><p>Bucket ini akan menjadi tempat uploaded files disimpan.</p><p><img src="'+e+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-bucket-ke-imgbed-project" tabindex="-1">2. Bind Bucket ke ImgBed Project <a class="header-anchor" href="#_2-bind-bucket-ke-imgbed-project" aria-label="Permalink to &quot;2. Bind Bucket ke ImgBed Project&quot;">​</a></h3><p>Pilih lokasi binding berdasarkan deployment type:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Saat menambahkan binding, field pentingnya:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Pilih bucket yang Anda buat.</td></tr></tbody></table><p>Variable name harus persis <code>img_r2</code>. Upload, read, dan delete R2 files semuanya bergantung pada binding name ini.</p><h3 id="_3-redeploy-project" tabindex="-1">3. Redeploy Project <a class="header-anchor" href="#_3-redeploy-project" aria-label="Permalink to &quot;3. Redeploy Project&quot;">​</a></h3><p>Setelah menyimpan binding, redeploy ImgBed agar Worker atau Pages runtime bisa mengakses <code>img_r2</code>.</p><h2 id="yang-akan-terlihat-di-imgbed" tabindex="-1">Yang Akan Terlihat di ImgBed <a class="header-anchor" href="#yang-akan-terlihat-di-imgbed" aria-label="Permalink to &quot;Yang Akan Terlihat di ImgBed&quot;">​</a></h2><p>Setelah R2 binding tersedia, buka:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li><code>Cloudflare R2</code> channel.</li></ol><p>System akan otomatis membuat satu fixed channel:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>Ini adalah fixed binding channel. Anda tidak perlu klik Add Channel untuk membuatnya, dan channel ini tidak bisa dihapus seperti regular channel.</p><h2 id="field-yang-bisa-diedit-di-admin-panel" tabindex="-1">Field yang Bisa Diedit di Admin Panel <a class="header-anchor" href="#field-yang-bisa-diedit-di-admin-panel" aria-label="Permalink to &quot;Field yang Bisa Diedit di Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>Mengontrol apakah R2 ikut dalam upload selection.</td><td>Yes</td></tr><tr><td>Account ID</td><td>Hanya dipakai saat quota limits aktif dan official R2 usage perlu di-query.</td><td>Recommended saat quota limits aktif</td></tr><tr><td>Bucket name</td><td>Hanya dipakai saat quota limits aktif dan official R2 usage perlu di-query.</td><td>Recommended saat quota limits aktif</td></tr><tr><td>Quota limit</td><td>Mengontrol apakah R2 channel ini ikut upload selection berdasarkan capacity.</td><td>No</td></tr><tr><td>Threshold</td><td>Menghentikan penulisan ke channel ini setelah usage mencapai percentage tertentu.</td><td>Required saat quota limits aktif</td></tr></tbody></table><p>Anda bisa copy Account ID dari account information panel di Cloudflare dashboard. Isi hanya jika ingin ImgBed query dan enforce R2 quota usage.</p><p><img src="'+t+'" alt="Get the Account ID" loading="lazy"></p><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buat R2 bucket di Cloudflare.</li><li>Buka Cloudflare settings untuk ImgBed project.</li><li>Tambahkan R2 bucket binding.</li><li>Set <code>Variable name</code> menjadi <code>img_r2</code>.</li><li>Pilih R2 bucket yang dibuat.</li><li>Save binding dan redeploy ImgBed.</li><li>Kembali ke ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Pastikan <code>Cloudflare R2</code> channel muncul dan enabled.</li></ol><p>Jika ingin R2 ikut upload selection berdasarkan capacity, aktifkan quota limit, lalu masukkan Account ID, bucket name, quota limit, dan threshold sebelum save.</p><p><img src="'+i+'" alt="Configure quota limits" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><ul><li>Fixed <code>Cloudflare R2</code> channel muncul di Upload Settings.</li><li>Channel card menunjukkan enabled.</li><li>Small test file berhasil di-upload, dan returned link terbuka normal.</li><li>Jika membuka file menampilkan <code>R2 database binding is not configured</code>, runtime belum menerima <code>img_r2</code> binding. Periksa binding name di Cloudflare dan redeploy project.</li></ul>',37)])])}const f=d(o,[["render",u]]);export{p as __pageData,f as default};
